function localStorageBackup2() {
    let el;
    if (localStorage.bodyBgRGB || localStorage.bodylightRGB) {
        el = document.querySelector("#switcher-dark-theme");
        if (el) el.checked = true;
        el = document.querySelector("#switcher-menu-dark");
        if (el) el.checked = true;
        el = document.querySelector("#switcher-header-dark");
        if (el) el.checked = true;
    }

    if (localStorage.bodyBgRGB) {
        let bgMap = {
            "12 23 91": "#switcher-background",
            "50 11 110": "#switcher-background1",
            "8 81 113": "#switcher-background2",
            "3 81 60": "#switcher-background3",
            "73 78 1": "#switcher-background4",
        };
        el = document.querySelector(bgMap[localStorage.bodyBgRGB]);
        if (el) el.checked = true;
    }

    if (localStorage.primaryRGB) {
        let primaryMap = {
            "118, 71, 229": "#switcher-primary",
            "63, 75, 236": "#switcher-primary1",
            "55, 125, 206": "#switcher-primary2",
            "1, 159, 162": "#switcher-primary3",
            "139, 149, 4": "#switcher-primary4",
        };
        el = document.querySelector(primaryMap[localStorage.primaryRGB]);
        if (el) el.checked = true;
    }

    if (localStorage.loaderEnable == "true") {
        el = document.querySelector("#switcher-loader-enable");
        if (el) el.checked = true;
    }
}
